const input = ($json && typeof $json === 'object' && !Array.isArray($json)) ? $json : {};
const nowIso = new Date().toISOString();

const clean = (v) => String(v ?? '').trim();
const isBlank = (v) => {
  const s = clean(v).toLowerCase();
  return s === '' || s === 'null' || s === 'undefined' || s === 'nan';
};
const isIsoDate = (v) => /^\d{4}-\d{2}-\d{2}$/.test(clean(v));

const ruleSrc = (input.rule && typeof input.rule === 'object' && !Array.isArray(input.rule))
  ? input.rule
  : ((input.ruleContext && typeof input.ruleContext === 'object' && !Array.isArray(input.ruleContext)) ? input.ruleContext : {});

const runSrc = (input.run && typeof input.run === 'object' && !Array.isArray(input.run))
  ? input.run
  : ((input.runContext && typeof input.runContext === 'object' && !Array.isArray(input.runContext)) ? input.runContext : {});

const traceSrc = (input.trace && typeof input.trace === 'object' && !Array.isArray(input.trace)) ? input.trace : {};
const ruleExecutionKey = [String($execution.id ?? 'manual'), String(Date.now()), String(Math.floor(Math.random() * 1e9))].join(':');
const trace = {
  parentExecutionId: traceSrc.parentExecutionId != null ? String(traceSrc.parentExecutionId) : (runSrc.executionId != null ? String(runSrc.executionId) : null),
  workflowExecutionId: String($execution.id ?? 'manual'),
  ruleExecutionKey,
};

const cfg = {
  invoicePipeId: 306859731,
  invoicePhaseId: 341350484,
  itemPipeId: 306859915,
  itemPhaseId: 341351580,
  activeItemPhaseId: '341306826',
  ruleLinkFieldId: 'id_da_regra_de_faturamento',
  competenciaFieldId: 'data_de_compet_ncia',
};

const ruleId = clean(ruleSrc.ruleId || ruleSrc.id || '');
const competenciaYMD = clean(ruleSrc.competenciaYMD || runSrc.competenciaYMD || '');
const compStart = clean(ruleSrc.compStart || runSrc.compStart || '');
const compEnd = clean(ruleSrc.compEnd || runSrc.compEnd || '');
const itemTemplateIds = Array.isArray(ruleSrc.itemTemplateIds)
  ? Array.from(new Set(ruleSrc.itemTemplateIds.map((x) => clean(x)).filter(Boolean)))
  : [];

const ctx = {
  contractVersion: 'fin_v3',
  trace,
  run: {
    executionId: runSrc.executionId != null ? String(runSrc.executionId) : String($execution.id ?? 'manual'),
    competenciaYMD,
    compStart,
    compEnd,
    todayDay: Number(runSrc.todayDay || 0),
  },
  rule: {
    ruleId: ruleId || null,
    ruleTitle: clean(ruleSrc.ruleTitle || ruleSrc.title || ''),
    prefetchDecision: clean(ruleSrc.prefetchDecision || 'new_rule_candidate') || 'new_rule_candidate',
    ruleFields: (ruleSrc.ruleFields && typeof ruleSrc.ruleFields === 'object' && !Array.isArray(ruleSrc.ruleFields)) ? ruleSrc.ruleFields : {},
    itemTemplateIds,
  },
  config: cfg,
  metricsDelta: {
    itemBatchQueries: 0,
    itemsFetched: 0,
    createInvoices: 0,
    createItems: 0,
    updateItemInvoiceLinks: 0,
    updateParcelasPagas: 0,
  },
  logs: [{ ts: nowIso, level: 'info', event: 'rule_input_received', ruleId: ruleId || null }],
  errors: [],
  createItemRequests: [],
  createdItemIds: [],
  parcelaUpdates: [],
  linkUpdates: [],
  eligibleItems: [],
  invoiceInputBase: null,
  invoiceId: null,
  existingInvoiceId: null,
  totals: { brl: 0, usd: 0 },
  hasFetchErrors: false,
  hasCreateItemErrors: false,
  hasParcelaErrors: false,
  terminal: { done: false, status: null, reason: null },
  startedAt: nowIso,
};

if (String(input.contractVersion || '') !== 'fin_v3' || String(input.itemType || '') !== 'rule_input') {
  ctx.terminal = { done: true, status: 'failed', reason: 'unexpected_payload_shape' };
  ctx.errors.push({ ts: nowIso, stage: 'init', reason: 'unexpected_payload_shape', details: { contractVersion: input.contractVersion ?? null, itemType: input.itemType ?? null } });
}

const validationErrors = [];
if (isBlank(ruleId)) validationErrors.push('missing_rule_id');
if (!isIsoDate(competenciaYMD)) validationErrors.push('invalid_competencia_ymd');
if (!isIsoDate(compStart)) validationErrors.push('invalid_comp_start');
if (!isIsoDate(compEnd)) validationErrors.push('invalid_comp_end');
if (isIsoDate(compStart) && isIsoDate(compEnd) && compStart > compEnd) validationErrors.push('comp_start_after_comp_end');

if (!ctx.terminal.done && validationErrors.length > 0) {
  ctx.terminal = { done: true, status: 'failed', reason: 'invalid_rule_input' };
  ctx.errors.push({ ts: nowIso, stage: 'init', reason: 'invalid_rule_input', details: { validationErrors } });
}

if (!ctx.terminal.done && itemTemplateIds.length === 0) {
  ctx.terminal = { done: true, status: 'skipped', reason: 'rule_has_no_item_templates' };
}

return [{ json: ctx }];

const inItems = $input.all().map((i) => (i && i.json && typeof i.json === 'object' && !Array.isArray(i.json)) ? i.json : {});
if (inItems.length === 0) {
  throw new Error('No template items received to consolidate');
}

const baseCtx = (inItems[0].ctx && typeof inItems[0].ctx === 'object' && !Array.isArray(inItems[0].ctx)) ? inItems[0].ctx : null;
if (!baseCtx) {
  throw new Error('Missing ctx on consolidate templates');
}

const ctx = JSON.parse(JSON.stringify(baseCtx));
const now = () => new Date().toISOString();
const log = (level, event, details = {}) => ctx.logs.push({ ts: now(), level, event, ...details });
const pushError = (stage, reason, details = {}) => ctx.errors.push({ ts: now(), stage, reason, details });

const fieldMap = (fields) => {
  const out = {};
  for (const f of (fields || [])) {
    const fid = f && f.field ? f.field.id : null;
    if (fid) out[fid] = f;
  }
  return out;
};
const pickScalar = (f) => {
  if (!f) return null;
  const rv = f.report_value;
  return (rv !== undefined && rv !== null && String(rv).trim() !== '') ? rv : f.value;
};
const parseNum = (v) => {
  if (v === undefined || v === null) return 0;
  if (typeof v === 'number' && Number.isFinite(v)) return v;
  let s = String(v).trim();
  if (!s) return 0;
  s = s.replace(/[^0-9,.-]/g, '');
  if (!s) return 0;
  if (s.includes(',') && s.includes('.')) {
    if (s.lastIndexOf(',') > s.lastIndexOf('.')) {
      s = s.replace(/\./g, '').replace(',', '.');
    } else {
      s = s.replace(/,/g, '');
    }
  } else if (s.includes(',')) {
    s = s.replace(',', '.');
  }
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
};
const extractIds = (f) => {
  if (!f) return [];
  const av = f.array_value;
  const ids = [];
  const push = (x) => {
    if (x === undefined || x === null) return;
    if (typeof x === 'object') {
      if (x.id != null) ids.push(String(x.id));
      else if (x.value != null) ids.push(String(x.value));
      else if (x.label != null) ids.push(String(x.label));
      else ids.push(JSON.stringify(x));
    } else {
      ids.push(String(x));
    }
  };

  if (Array.isArray(av)) {
    for (const x of av) push(x);
  } else {
    const v = pickScalar(f);
    if (Array.isArray(v)) {
      for (const x of v) push(x);
    } else if (typeof v === 'string') {
      const ms = v.match(/[0-9]+/g);
      if (ms) for (const x of ms) ids.push(String(x));
      else if (v.trim() !== '') ids.push(v.trim());
    } else if (v != null) {
      push(v);
    }
  }

  return Array.from(new Set(ids.filter((s) => s && String(s).trim() !== ''))).map(String);
};
const extractList = (f) => {
  if (!f) return [];
  const av = f.array_value;
  let out = [];
  if (Array.isArray(av)) {
    out = av.map((x) => String(x));
  } else {
    const v = pickScalar(f);
    if (Array.isArray(v)) out = v.map((x) => String(x));
    else if (typeof v === 'string') {
      const s = v.trim();
      if (!s) out = [];
      else if (s.startsWith('[')) {
        try {
          const p = JSON.parse(s);
          if (Array.isArray(p)) out = p.map((x) => String(x));
          else out = [String(p)];
        } catch (_err) {
          out = s.split(',').map((x) => x.trim()).filter(Boolean);
        }
      } else {
        out = s.split(',').map((x) => x.trim()).filter(Boolean);
      }
    } else if (v != null) {
      out = [String(v)];
    }
  }
  return Array.from(new Set(out.filter(Boolean)));
};

const allowed = new Set(['afiliados_que_comp_em_a_cobran_a','base_do_c_lculo_percentual','categorias_do_saas_isentas_ou_com_desconto','data_de_compet_ncia','desconto_no_valor_vari_vel_do_saas_para_a_b','desconto_no_valor_vari_vel_do_saas_para_e_s','desconto_no_valor_vari_vel_do_saas_para_espa_os','desconto_no_valor_vari_vel_do_saas_para_hospedagem','desconto_no_valor_vari_vel_do_saas_para_outros','h_algum_desconto_nesse_item','id_backoffice_do_afiliado','id_da_fatura','id_do_item_usado_como_template_fin_02','modelo_de_cobran_a','moeda_da_fatura','observa_es_sobre_descontos_e_isen_es','percentual_a_ser_aplicado_na_base','percentual_de_desconto_a_ser_aplicado','produto','quantidade','status','tipo_de_desconto_a_b_1','tipo_de_desconto_e_s','tipo_de_desconto_espa_os','tipo_de_desconto_hospedagem','tipo_de_desconto_no_item','tipo_de_desconto_outros','tipo_de_item','unidade_de_cobran_a','valor_base_saas_categoria_a_b_brl','valor_base_saas_categoria_a_b_usd','valor_base_saas_categoria_e_s_brl','valor_base_saas_categoria_e_s_usd','valor_base_saas_categoria_espa_os_brl','valor_base_saas_categoria_espa_os_usd','valor_base_saas_categoria_hospedagem_brl','valor_base_saas_categoria_hospedagem_usd','valor_base_saas_categoria_outros_brl','valor_base_saas_categoria_outros_usd','valor_de_base_brl','valor_de_base_usd','valor_do_imposto_a_ser_isento_a_b','valor_do_imposto_a_ser_isento_e_s','valor_do_imposto_a_ser_isento_espa_os','valor_do_imposto_a_ser_isento_hospedagem','valor_do_imposto_a_ser_isento_outros','valor_nominal_a_ser_descontado_brl','valor_nominal_a_ser_descontado_usd','valor_total_do_item_brl','valor_total_do_item_com_descontos_brl','valor_total_do_item_com_descontos_usd','valor_total_do_item_usd','valor_unit_rio_brl','valor_unit_rio_usd','statement_2c441aae_a317_42eb_81c2_c3a06c8daae7','statement_4a274d3d_6286_453b_9e74_46b058076519','statement_4f0c1eda_5fed_4d79_8cdd_ac05c377995d','statement_7140fc81_0523_47c6_a23b_c31ede660ea4']);
const special = { tipo_de_desconto_no_item_1: 'tipo_de_desconto_no_item', subtotal_do_item_brl: 'valor_total_do_item_brl', subtotal_do_item_usd: 'valor_total_do_item_usd' };

const compStart = String(ctx.run.compStart || '');
const compEnd = String(ctx.run.compEnd || '');
const activePhase = String(ctx.config.activeItemPhaseId || '');

let fetchTransportErrors = 0;
let fetchLogicalErrors = 0;
let totalBrl = 0;
let totalUsd = 0;
const eligibleItems = [];
const createItemRequests = [];

for (const it of inItems) {
  const templateItemId = String(it.templateItemId || '').trim();
  const gqlErrors = Array.isArray(it.errors) ? it.errors : [];
  if (it.error) {
    fetchTransportErrors += 1;
    ctx.hasFetchErrors = true;
    pushError('fetch_template_item', 'fetch_template_item_error', { templateItemId: templateItemId || null, details: it.error });
    continue;
  }
  if (gqlErrors.length > 0) {
    fetchLogicalErrors += 1;
    ctx.hasFetchErrors = true;
    pushError('fetch_template_item', 'fetch_template_item_error', { templateItemId: templateItemId || null, gqlErrors });
    continue;
  }

  const card = it.data?.card;
  if (!card || !card.id) {
    fetchLogicalErrors += 1;
    ctx.hasFetchErrors = true;
    pushError('fetch_template_item', 'fetch_template_item_error', { templateItemId: templateItemId || null, reason: 'missing_card_data' });
    continue;
  }

  const phaseId = card.current_phase && card.current_phase.id ? String(card.current_phase.id) : '';
  if (phaseId !== activePhase) {
    log('info', 'item_skip_inactive_phase', { templateItemId: String(card.id), phaseId, expectedPhaseId: activePhase });
    continue;
  }

  const fm = fieldMap(card.fields || []);
  const start = String(pickScalar(fm['data_de_in_cio_do_faturamento']) || '').slice(0, 10);
  const end = String(pickScalar(fm['data_de_fim_do_faturamento']) || '').slice(0, 10);

  if (start && start > compEnd) {
    log('info', 'item_skip_not_started', { templateItemId: String(card.id), start, compEnd });
    continue;
  }
  if (end && end < compStart) {
    log('info', 'item_skip_ended', { templateItemId: String(card.id), end, compStart });
    continue;
  }

  const periodicidade = String(pickScalar(fm['periodicidade']) || '').trim();
  let parcelado = null;
  if (periodicidade === 'Parcelado') {
    const pagas = parseInt(String(pickScalar(fm['parcelas_pagas']) || '0').match(/[0-9]+/) ? String(pickScalar(fm['parcelas_pagas'])).match(/[0-9]+/)[0] : '0', 10);
    const total = parseInt(String(pickScalar(fm['quantidade_de_parcelas_totais']) || '0').match(/[0-9]+/) ? String(pickScalar(fm['quantidade_de_parcelas_totais'])).match(/[0-9]+/)[0] : '0', 10);
    if (!(total > 0)) {
      pushError('filter_templates', 'create_item_logical_error', { templateItemId: String(card.id), reason: 'invalid_total_parcelas', pagas, total });
      ctx.hasCreateItemErrors = true;
      continue;
    }
    if (pagas >= total) {
      log('info', 'item_skip_parcelado_done', { templateItemId: String(card.id), pagas, total });
      continue;
    }
    parcelado = { newParcelasPagas: pagas + 1 };
  }

  const currency = String(pickScalar(fm['moeda_da_fatura']) || '').trim();
  let brl = 0;
  let usd = 0;
  if (currency.startsWith('USD')) {
    usd = parseNum(pickScalar(fm['valor_total_do_item_com_descontos_usd']) ?? pickScalar(fm['subtotal_do_item_usd']));
  } else if (currency.startsWith('BRL')) {
    brl = parseNum(pickScalar(fm['valor_total_do_item_com_descontos_brl']) ?? pickScalar(fm['subtotal_do_item_brl']));
  } else {
    brl = parseNum(pickScalar(fm['valor_total_do_item_com_descontos_brl']) ?? pickScalar(fm['subtotal_do_item_brl']));
    usd = parseNum(pickScalar(fm['valor_total_do_item_com_descontos_usd']) ?? pickScalar(fm['subtotal_do_item_usd']));
  }

  totalBrl += brl;
  totalUsd += usd;

  const fa = [];
  fa.push({ field_id: 'data_de_compet_ncia', field_value: String(ctx.run.competenciaYMD || '') });
  fa.push({ field_id: 'id_do_item_usado_como_template_fin_02', field_value: String(card.id) });
  fa.push({ field_id: 'status', field_value: 'Ativo' });

  for (const f of (card.fields || [])) {
    const fid = f && f.field ? f.field.id : null;
    if (!fid) continue;
    const target = special[fid] || fid;
    if (!allowed.has(target)) continue;
    if (target === 'data_de_compet_ncia' || target === 'id_do_item_usado_como_template_fin_02' || target === 'status' || target === 'id_da_fatura') continue;
    const type = f && f.field ? String(f.field.type || '') : '';
    let val = null;
    if (type === 'connector' || type === 'checklist_horizontal' || type === 'checklist_vertical') {
      val = extractIds(f);
    } else {
      val = pickScalar(f);
    }
    if (val === undefined || val === null) continue;
    if (Array.isArray(val) && val.length === 0) continue;
    if (typeof val === 'string' && val.trim() === '') continue;
    fa.push({ field_id: target, field_value: val });
  }

  const createReq = {
    templateItemId: String(card.id),
    shouldUpdateParcelas: Boolean(parcelado),
    newParcelasPagas: parcelado ? parcelado.newParcelasPagas : null,
    input: {
      pipe_id: Number(ctx.config.itemPipeId),
      phase_id: Number(ctx.config.itemPhaseId),
      parent_ids: [String(card.id)],
      title: `Item ${String(ctx.run.competenciaYMD || '').slice(0, 7)} - ${String(card.id)}`,
      fields_attributes: fa,
    },
  };

  eligibleItems.push({ templateItemId: String(card.id), periodicidade, totalBrl: brl, totalUsd: usd });
  createItemRequests.push(createReq);
}

ctx.metricsDelta.itemBatchQueries = inItems.length;
ctx.metricsDelta.itemsFetched = eligibleItems.length;
ctx.eligibleItems = eligibleItems;
ctx.createItemRequests = createItemRequests;
ctx.totals = { brl: totalBrl, usd: totalUsd };

const rf = (ctx.rule.ruleFields && typeof ctx.rule.ruleFields === 'object' && !Array.isArray(ctx.rule.ruleFields)) ? ctx.rule.ruleFields : {};
const invoiceFields = [];
const pushField = (fid, val) => {
  if (val === undefined || val === null) return;
  if (Array.isArray(val) && val.length === 0) return;
  if (typeof val === 'string' && val.trim() === '') return;
  invoiceFields.push({ field_id: fid, field_value: val });
};

pushField('clientes_na_fatura', extractIds(rf['clientes_na_fatura']));
pushField('rede_na_fatura', extractIds(rf['rede_na_fatura']));
pushField('contatos_que_receber_o_a_fatura', extractIds(rf['contatos_que_receber_o_a_fatura']));
pushField('forma_de_pagamento', extractList(rf['forma_de_pagamento']));
pushField('identificador_fiscal_na_fatura', String(pickScalar(rf['identificador_fiscal_na_fatura']) || ''));
pushField('tipo_de_cliente_final', String(pickScalar(rf['tipo_de_cliente_final']) || ''));
pushField('moeda_do_teto_de_faturamento', extractList(rf['moeda_do_teto_de_faturamento']));
const tetoBrl = parseNum(pickScalar(rf['teto_de_faturamento_brl']));
const tetoUsd = parseNum(pickScalar(rf['teto_de_faturamento_usd']));
if (tetoBrl) pushField('teto_de_faturamento_brl', tetoBrl);
if (tetoUsd) pushField('teto_de_faturamento_usd', tetoUsd);
pushField('etiquetas', extractList(rf['etiquetas']));
pushField('id_da_regra_de_faturamento', ctx.rule.ruleId);
pushField('data_de_compet_ncia', String(ctx.run.competenciaYMD || ''));
pushField('valor_total_da_fatura_brl', totalBrl);
pushField('valor_total_da_fatura_usd', totalUsd);

ctx.invoiceInputBase = {
  pipe_id: Number(ctx.config.invoicePipeId),
  phase_id: Number(ctx.config.invoicePhaseId),
  title: `Fatura ${String(ctx.run.competenciaYMD || '').slice(0, 7)} - Regra ${String(ctx.rule.ruleId || '')}`,
  fields_attributes: invoiceFields,
};

if (eligibleItems.length === 0) {
  if (fetchTransportErrors > 0 || fetchLogicalErrors > 0) {
    ctx.terminal = { done: true, status: 'failed', reason: 'fetch_template_item_error' };
  } else {
    ctx.terminal = { done: true, status: 'skipped', reason: 'no_eligible_items_after_filters' };
  }
}

return [{ json: ctx }];

const inItems = $input.all().map((i) => (i && i.json && typeof i.json === 'object' && !Array.isArray(i.json)) ? i.json : {});
if (inItems.length === 0) {
  throw new Error('No items to consolidate create item stage');
}

const baseCtx = (inItems[0].ctx && typeof inItems[0].ctx === 'object' && !Array.isArray(inItems[0].ctx)) ? inItems[0].ctx : null;
if (!baseCtx) {
  throw new Error('Missing ctx on consolidate create item stage');
}

const ctx = JSON.parse(JSON.stringify(baseCtx));
const now = () => new Date().toISOString();
const pushError = (reason, details = {}) => ctx.errors.push({ ts: now(), stage: 'create_item', reason, details });

let transportErrors = 0;
let logicalErrors = 0;
const created = [];
const parcelaUpdates = [];

for (const it of inItems) {
  const req = (it.createReq && typeof it.createReq === 'object' && !Array.isArray(it.createReq)) ? it.createReq : {};
  if (it.error) {
    transportErrors += 1;
    ctx.hasCreateItemErrors = true;
    pushError('create_item_transport_error', { templateItemId: req.templateItemId ?? null, details: it.error });
    continue;
  }

  const gqlErrors = Array.isArray(it.errors) ? it.errors : [];
  if (gqlErrors.length > 0) {
    logicalErrors += 1;
    ctx.hasCreateItemErrors = true;
    pushError('create_item_logical_error', { templateItemId: req.templateItemId ?? null, gqlErrors });
    continue;
  }

  const create = it.data?.createCard;
  const userErrors = Array.isArray(create?.userErrors) ? create.userErrors : (Array.isArray(create?.user_errors) ? create.user_errors : []);
  const createdId = create?.card?.id != null ? String(create.card.id) : null;
  if (userErrors.length > 0 || !createdId) {
    logicalErrors += 1;
    ctx.hasCreateItemErrors = true;
    pushError('create_item_logical_error', { templateItemId: req.templateItemId ?? null, userErrors, hasCreatedId: Boolean(createdId) });
    continue;
  }

  created.push(createdId);
  if (req.shouldUpdateParcelas === true && req.newParcelasPagas != null && req.templateItemId != null) {
    parcelaUpdates.push({
      templateItemId: String(req.templateItemId),
      newParcelasPagas: Number(req.newParcelasPagas),
    });
  }
}

ctx.createdItemIds = Array.from(new Set(created));
ctx.parcelaUpdates = parcelaUpdates;
ctx.metricsDelta.createItems = ctx.createdItemIds.length;

if (ctx.createdItemIds.length === 0) {
  let reason = 'no_created_items_for_invoice';
  if (transportErrors > 0 && logicalErrors === 0) reason = 'create_item_transport_error';
  if (logicalErrors > 0 && transportErrors === 0) reason = 'create_item_logical_error';
  ctx.terminal = { done: true, status: 'failed', reason };
}

return [{ json: ctx }];

const inItems = $input.all().map((i) => (i && i.json && typeof i.json === 'object' && !Array.isArray(i.json)) ? i.json : {});
if (inItems.length === 0) {
  throw new Error('No items to consolidate parcelas stage');
}

const baseCtx = (inItems[0].ctx && typeof inItems[0].ctx === 'object' && !Array.isArray(inItems[0].ctx)) ? inItems[0].ctx : null;
if (!baseCtx) {
  throw new Error('Missing ctx on consolidate parcelas stage');
}

const ctx = JSON.parse(JSON.stringify(baseCtx));
const now = () => new Date().toISOString();

for (const it of inItems) {
  const req = (it.updateReq && typeof it.updateReq === 'object' && !Array.isArray(it.updateReq)) ? it.updateReq : {};
  if (it.error) {
